customMethods.script:
cellId = BlueRidge.Common.Util.extractQualifiedValues(cellId)
row = BlueRidge.Location.Location.findCellById(self.view.custom.cells, cellId)
if row is None:
	return
self.session.custom.cell = {"locationId": row.get("value"), "code": row.get("code") or "", "name": row.get("name") or ""}

messageHandlers.script:
action = payload.get("action") if payload else None
if action == "cancel":
	return
result = self.submitCreate()
if result and result.get("Status"):
	if action == "clear":
		self.cancelDraft()
	elif action == "another":
		self.clearForAnother()
